import React from 'react';
import { Link } from 'react-router-dom';

const Header: React.FC = () => {
    return (
        <header className="header">
            <div className="container">
                <nav className="navbar">
                    <div className="logo">
                        <Link to="/">Channel4Me</Link>
                    </div>

                    <ul className="nav-menu">
                        <li><Link to="/" className="nav-link">Home</Link></li>
                        <li><Link to="/" className="nav-link">About</Link></li>
                        <li><Link to="/" className="nav-link">Contact</Link></li>
                    </ul>

                    <div className="nav-buttons">
                        <Link to="/doctor/login" className="btn btn-login">Doctor Login</Link>
                        <Link to="/doctor/register/step1" className="btn btn-primary">Doctor Sign Up</Link>
                    </div>
                </nav>
            </div>
        </header>
    );
};

export default Header;
